// MCP OAuth2 PKCE 交互式登录工具
// Generated by mcp-to-quickjs for {{DIR_NAME}}
//
// === 标准 MCP Authorization 流程 ===
// 1. MCP 客户端 → 服务器: 无 token 请求 → 401 + WWW-Authenticate
// 2. 客户端发现: 从 WWW-Authenticate 解析 resource_metadata → 获取授权服务器地址
// 3. 动态注册: POST /oauth2/register → 获取 public client_id
// 4. PKCE 授权: 浏览器授权 → 获取 authorization_code
// 5. Token 交换: code + code_verifier → access_token + refresh_token
// 6. Token 使用: Authorization: Bearer <access_token>
//
// Usage:
//   ./run.sh auth-login.js                    交互式完整授权
//   ./run.sh auth-login.js --new              强制新会话
//   ./run.sh auth-login.js --url '<回调URL>'   粘贴回调URL自动完成
//   ./run.sh auth-login.js --refresh          刷新 token

// === 服务端配置（由 mcp-to-quickjs 生成） ===
const AUTH_SERVER = "{{AUTH_SERVER}}";           // 从 401 WWW-Authenticate 发现
const MCP_RESOURCE = "{{MCP_URL}}";              // 目标 MCP 服务地址
const DIR_NAME = "{{DIR_NAME}}";                 // 目录名（用于临时文件）
const REDIRECT_URI = "http://localhost:8899/callback";
const SCOPE = "{{SCOPE}}";                       // 通常 "openid profile offline offline_access"
const STATE_FILE = "/tmp/" + DIR_NAME + "-auth.json";
const CONFIG_FILE = "../config.json";
const SESSION_TTL = 10 * 60 * 1000;              // 会话有效期 10 分钟

// === Shell 辅助 ===

function shellOut(cmd) {
    let outFile = "/tmp/_shout_" + Date.now() + "_" + Math.random().toString(36).slice(2, 8);
    os.exec(["sh", "-c", cmd + " > " + outFile + " 2>&1"]);
    let result = "";
    try {
        let f = std.open(outFile, "r");
        result = f.readAsString().trim();
        f.close();
    } catch (e) {}
    try { os.remove(outFile); } catch (e) {}
    return result;
}

function fileGetContents(path) {
    try { let f = std.open(path, "r"); let s = f.readAsString().trim(); f.close(); return s; }
    catch (e) { return null; }
}

function filePutContents(path, content) {
    let f = std.open(path, "w"); f.puts(content); f.close();
}

// === 步骤 1: 动态注册客户端 (RFC 7591) ===

var _registeredClientId = null;

function registerClient() {
    print("正在注册 OAuth2 客户端...");
    let regUrl = AUTH_SERVER + "/oauth2/register";

    let body = JSON.stringify({
        client_name: DIR_NAME + "-mcp-quickjs",
        grant_types: ["authorization_code", "refresh_token"],
        response_types: ["code"],
        redirect_uris: [REDIRECT_URI],
        token_endpoint_auth_method: "none",
        application_type: "native"
    });

    let tmpBody = "/tmp/_reg_body_" + Date.now();
    let tmpResp = "/tmp/_reg_resp_" + Date.now();
    filePutContents(tmpBody, body);

    let exitCode = os.exec([
        "curl", "-s", "-S", "-X", "POST",
        "-H", "Content-Type: application/json",
        "-d", "@" + tmpBody,
        "--output", tmpResp,
        "--max-time", "15",
        regUrl
    ]);

    try { os.remove(tmpBody); } catch (e) {}

    if (exitCode !== 0) {
        print("ERROR: 客户端注册失败 (curl exit " + exitCode + ")");
        return null;
    }

    let resp = null;
    try { resp = JSON.parse(fileGetContents(tmpResp)); } catch (e) {}
    try { os.remove(tmpResp); } catch (e) {}

    if (resp && resp.client_id) {
        print("  注册成功: " + resp.client_id);
        _registeredClientId = resp.client_id;
        return resp.client_id;
    }

    print("ERROR: 客户端注册失败，响应: " + (resp ? JSON.stringify(resp) : "(empty)"));
    return null;
}

function getClientId() {
    if (_registeredClientId) return _registeredClientId;
    return registerClient();
}

// === 步骤 2: PKCE 参数生成 ===

function generateCodeVerifier() {
    return shellOut("openssl rand -base64 48 | tr -d '=\\n' | tr '/+' '_-'") || null;
}

function generateCodeChallenge(verifier) {
    let tmpIn = "/tmp/_pkce_v_" + Date.now();
    filePutContents(tmpIn, verifier);
    let result = shellOut(
        "cat " + tmpIn + " | openssl dgst -sha256 -binary | openssl base64 | tr -d '=\\n' | tr '/+' '_-'"
    );
    try { os.remove(tmpIn); } catch (e) {}
    return result || null;
}

function generateState() {
    return shellOut("openssl rand -hex 16") || null;
}

// === 步骤 3: 会话管理（持久化 code_verifier + state，防止重复运行覆盖） ===

function loadSession() {
    let raw = fileGetContents(STATE_FILE);
    if (!raw) return null;
    try {
        let s = JSON.parse(raw);
        let age = Date.now() - (s.created_at || 0);
        if (age > SESSION_TTL) {
            print("(已有会话已过期，创建新会话)");
            try { os.remove(STATE_FILE); } catch (e) {}
            return null;
        }
        return s;
    } catch (e) {
        try { os.remove(STATE_FILE); } catch (e) {}
        return null;
    }
}

function saveSession(state, verifier, clientId) {
    filePutContents(STATE_FILE, JSON.stringify({
        state: state,
        code_verifier: verifier,
        client_id: clientId,
        created_at: Date.now()
    }));
}

function clearSession() {
    try { os.remove(STATE_FILE); } catch (e) {}
}

// === 步骤 4: Token 持久化（写入 config.json，由 config.js 读取） ===

function saveConfig(accessToken, refreshToken, expiresIn) {
    let expiresAt = Date.now() + (expiresIn - 120) * 1000;
    filePutContents(CONFIG_FILE, JSON.stringify({
        AUTH_HEADER: "Bearer " + accessToken,
        REFRESH_TOKEN: refreshToken || "",
        EXPIRES_AT: expiresAt
    }, null, 2));
}

function loadConfig() {
    let raw = fileGetContents(CONFIG_FILE);
    return raw ? JSON.parse(raw) : null;
}

// === 步骤 5: Token 端点请求 ===

function httpTokenRequest(clientId, params) {
    let tmpBody = "/tmp/_tk_body_" + Date.now();
    let tmpResp = "/tmp/_tk_resp_" + Date.now();
    let tmpHeaders = "/tmp/_tk_hdr_" + Date.now();

    let parts = [];
    for (let key in params) {
        parts.push(key + "=" + encodeURIComponent(params[key]));
    }

    filePutContents(tmpBody, parts.join("&"));

    // Basic auth: base64(client_id:)
    let escapedId = clientId.replace(/'/g, "'\\''");
    let basicAuth = shellOut("printf '%s' '" + escapedId + ":' | openssl base64 | tr -d '\\n'");

    let exitCode = os.exec([
        "curl", "-s", "-S", "-X", "POST",
        "-H", "Content-Type: application/x-www-form-urlencoded",
        "-H", "Authorization: Basic " + (basicAuth || "test"),
        "-d", "@" + tmpBody,
        "-D", tmpHeaders,
        "--output", tmpResp,
        "--max-time", "30",
        AUTH_SERVER + "/oauth2/token"
    ]);

    try { os.remove(tmpBody); } catch (e) {}

    let respBody = fileGetContents(tmpResp) || "";
    let respHeaders = fileGetContents(tmpHeaders) || "";
    try { os.remove(tmpResp); os.remove(tmpHeaders); } catch (e) {}

    let httpStatus = 0;
    let headerLines = respHeaders.split("\n");
    if (headerLines.length > 0) {
        let m = headerLines[0].match(/HTTP\/[\d.]+\s+(\d+)/);
        if (m) httpStatus = parseInt(m[1]);
    }

    let resp = null;
    try { resp = JSON.parse(respBody); } catch (e) {}

    return { exitCode, httpStatus, resp, rawBody: respBody };
}

// === 步骤 6: 解析回调 URL ===

function parseCallbackUrl(urlStr) {
    let qIdx = urlStr.indexOf("?");
    if (qIdx < 0) return { code: null, error: "URL 中没有找到参数" };

    let query = urlStr.substring(qIdx + 1);
    let params = {};
    for (let pair of query.split("&")) {
        let eqIdx = pair.indexOf("=");
        if (eqIdx > 0) {
            params[pair.substring(0, eqIdx)] = decodeURIComponent(pair.substring(eqIdx + 1));
        }
    }

    if (params.error) return { code: null, error: params.error + ": " + (params.error_description || "") };
    if (!params.code) return { code: null, error: "回调 URL 中未找到 code 参数" };
    return { code: params.code, state: params.state || null };
}

// === 交互流程: 生成授权 URL ===

function doGenerateUrl(forceNew) {
    let session = forceNew ? null : loadSession();

    // 1) 注册客户端（如果还没注册）
    let clientId;
    if (session && session.client_id) {
        clientId = session.client_id;
        _registeredClientId = clientId;
    } else {
        clientId = getClientId();
        if (!clientId) return;
    }

    if (session) {
        // 复用已有会话
        let age = Math.round((Date.now() - session.created_at) / 1000);
        print("");
        print("=== 复用现有认证会话 (已创建 " + age + "s) ===");
        print("");
        print("如需要重新创建，请运行: ./run.sh auth-login.js --new");
        print("");

        let challenge = generateCodeChallenge(session.code_verifier);
        if (!challenge) { print("ERROR: 无法生成 code_challenge"); return; }
        print(buildAuthUrl(clientId, challenge, session.state));
        print("");
        print("授权完成后将浏览器地址栏中的完整 URL 复制下来，运行:");
        print("");
        print('  ./run.sh auth-login.js --url "<粘贴的URL>"');
        print("");
        return;
    }

    // 2) 新会话：生成 PKCE 参数
    let verifier = generateCodeVerifier();
    if (!verifier) { print("ERROR: 生成 code_verifier 失败"); return; }

    let challenge = generateCodeChallenge(verifier);
    if (!challenge) { print("ERROR: 生成 code_challenge 失败"); return; }

    let state = generateState();
    if (!state) { print("ERROR: 生成 state 失败"); return; }

    saveSession(state, verifier, clientId);

    // 3) 输出授权 URL
    print("");
    print("=== MCP OAuth2 授权 ===");
    print("  授权服务器: " + AUTH_SERVER);
    print("  目标服务:   " + MCP_RESOURCE);
    print("  客户端 ID:  " + clientId);
    print("");
    print("请在浏览器中打开以下链接完成授权:");
    print("");
    print(buildAuthUrl(clientId, challenge, state));
    print("");
    print("授权完成后将浏览器地址栏中的完整 URL 复制下来，运行:");
    print("");
    print('  ./run.sh auth-login.js --url "<粘贴的URL>"');
    print("");
}

function buildAuthUrl(clientId, challenge, state) {
    let params = [];
    params.push("client_id=" + encodeURIComponent(clientId));
    params.push("response_type=code");
    params.push("redirect_uri=" + encodeURIComponent(REDIRECT_URI));
    params.push("code_challenge=" + encodeURIComponent(challenge));
    params.push("code_challenge_method=S256");
    params.push("resource=" + encodeURIComponent(MCP_RESOURCE));
    params.push("state=" + encodeURIComponent(state));
    params.push("scope=" + encodeURIComponent(SCOPE));
    return AUTH_SERVER + "/oauth2/authorize?" + params.join("&");
}

// === Token 交换 ===

function doExchangeFromUrl(urlStr) {
    let session = loadSession();
    if (!session) {
        print("ERROR: 未找到有效的认证会话。请先运行: ./run.sh auth-login.js");
        return;
    }

    let parsed = parseCallbackUrl(urlStr);
    if (parsed.error) {
        print("ERROR: " + parsed.error);
        return;
    }

    // 验证 state（防止 CSRF）
    if (parsed.state && parsed.state !== session.state) {
        print("ERROR: state 不匹配！");
        print("  期望: " + session.state);
        print("  收到: " + parsed.state);
        print("  这说明回调 URL 不是本次授权会话产生的。");
        print("  请重新运行: ./run.sh auth-login.js --new");
        return;
    }

    print("正在交换授权码...");

    let r = httpTokenRequest(session.client_id, {
        client_id: session.client_id,
        grant_type: "authorization_code",
        code: parsed.code,
        code_verifier: session.code_verifier,
        redirect_uri: REDIRECT_URI
    });

    if (r.exitCode !== 0) {
        print("ERROR: curl 返回 " + r.exitCode);
        if (r.rawBody) print("响应: " + r.rawBody);
        return;
    }

    if (r.httpStatus !== 200) {
        print("ERROR: HTTP " + r.httpStatus);
        if (r.resp && r.resp.error) {
            print("  " + r.resp.error + " — " + (r.resp.error_description || ""));
        } else {
            print("  响应: " + (r.rawBody || "(empty)"));
        }
        if (r.httpStatus === 400 && r.resp && r.resp.error === "invalid_grant") {
            print("");
            print("可能的原因:");
            print("  1. 授权码已过期（通常几分钟内有效）");
            print("  2. 授权码已被使用过（每次只能使用一次）");
            print("  3. 会话不匹配（请用 --new 创建新会话重新授权）");
            print("");
            print("解决方案: 运行 ./run.sh auth-login.js --new 重新授权");
        }
        return;
    }

    if (!r.resp || !r.resp.access_token) {
        print("ERROR: 服务器未返回 access_token");
        print("响应: " + (r.rawBody || "(empty)"));
        return;
    }

    saveConfig(r.resp.access_token, r.resp.refresh_token || "", r.resp.expires_in || 604800);
    clearSession();

    let days = (r.resp.expires_in / 86400).toFixed(1);
    print("");
    print("=== 认证成功 ===");
    print("  access_token 已保存到 " + CONFIG_FILE + "（有效期 " + days + " 天）");
    if (r.resp.refresh_token) print("  refresh_token 已保存");
    print("");
    print("现在可以运行: ./run.sh mcp.js list");
    print("");
}

// === Token 刷新 ===

function doRefresh() {
    let config = loadConfig();
    if (!config || !config.REFRESH_TOKEN) {
        print("ERROR: 未找到 refresh_token，请先完成首次授权");
        return;
    }

    // 需要 client_id 来刷新，从注册获取
    let clientId = getClientId();
    if (!clientId) return;

    print("正在刷新 access_token...");

    let r = httpTokenRequest(clientId, {
        client_id: clientId,
        grant_type: "refresh_token",
        refresh_token: config.REFRESH_TOKEN
    });

    if (r.exitCode !== 0 || r.httpStatus !== 200 || !r.resp || !r.resp.access_token) {
        let msg = "请求失败";
        if (r.resp && r.resp.error) msg = r.resp.error + " — " + r.resp.error_description;
        print("ERROR: " + msg);
        print("请重新运行: ./run.sh auth-login.js --new");
        return;
    }

    saveConfig(r.resp.access_token, r.resp.refresh_token || "", r.resp.expires_in || 604800);
    print("=== 刷新成功 ===");
}

// === 验证当前 token 状态 ===

function doStatus() {
    let config = loadConfig();
    if (!config || !config.AUTH_HEADER) {
        print("未登录。请运行: ./run.sh auth-login.js");
        return;
    }
    let now = Date.now();
    let remaining = (config.EXPIRES_AT - now) / 1000;
    if (remaining > 0) {
        let days = Math.floor(remaining / 86400);
        let hours = Math.floor((remaining % 86400) / 3600);
        print("已登录。token 剩余有效期: " + days + "天 " + hours + "小时");
    } else {
        print("token 已过期。请运行: ./run.sh auth-login.js --refresh");
    }
}

// === Main ===

let args = scriptArgs.slice(1);

if (args.length === 0) {
    doGenerateUrl(false);
} else if (args[0] === "--new") {
    clearSession();
    doGenerateUrl(true);
} else if (args[0] === "--url" && args.length >= 2) {
    doExchangeFromUrl(args[1]);
} else if (args[0] === "--refresh") {
    doRefresh();
} else if (args[0] === "--status") {
    doStatus();
} else if (args[0] === "--help" || args[0] === "-h") {
    print("MCP OAuth2 PKCE 交互式登录工具 (" + DIR_NAME + ")");
    print("");
    print("标准 MCP Authorization 流程 (OAuth2.1 + PKCE + 动态客户端注册):");
    print("  ./run.sh auth-login.js                    生成/复用授权链接");
    print("  ./run.sh auth-login.js --new              强制创建新授权会话");
    print("  ./run.sh auth-login.js --url '<回调URL>'   粘贴回调URL，自动交换token");
    print("");
    print("Token 管理:");
    print("  ./run.sh auth-login.js --status           查看 token 状态");
    print("  ./run.sh auth-login.js --refresh          刷新 access_token");
    print("");
    print("授权服务器: " + AUTH_SERVER);
    print("目标服务:   " + MCP_RESOURCE);
} else {
    print("未知参数: " + args.join(" "));
    print("使用 --help 查看帮助");
}
